    10	
    11	// Mark types that should be converted from wrapper elements to text marks
    12	const MARK_TYPES = new Set(['bold', 'italic', 'strike', 'underline', 'code', 'link']);
    13	
    14	/**
    15	 * Check if an element is an inline mark (bold, italic, etc.) rather than a block element
    16	 */
    17	function isMarkElement(nodeName: string): boolean {
    18	  return MARK_TYPES.has(nodeName);
    19	}
    20	
    21	/**
    22	 * Extract text content and marks from a mark element (e.g., <bold>text</bold>)
    23	 * Returns array of text nodes with marks applied
    24	 */
    25	function extractTextWithMarks(element: Y.XmlElement, inheritedMarks: TipTapMark[] = []): TipTapNode[] {
    26	  const nodeName = element.nodeName;
    27	  const attrs = element.getAttributes();
    28	
    29	  // Build mark for this element
    30	  const mark: TipTapMark = { type: nodeName };
    31	  if (nodeName === 'link' && attrs.href) {
    32	    mark.attrs = { href: attrs.href, target: attrs.target || '_blank' };
    33	  }
    34	
    35	  const currentMarks = [...inheritedMarks, mark];
    36	  const result: TipTapNode[] = [];
    37	
    38	  for (let i = 0; i < element.length; i++) {
    39	    const child = element.get(i);
    40	    if (child instanceof Y.XmlText) {
    41	      const text = child.toString();
    42	      if (text) {
    43	        result.push({ type: 'text', text, marks: currentMarks });
    44	      }
    45	    } else if (child instanceof Y.XmlElement) {
    46	      if (isMarkElement(child.nodeName)) {
    47	        // Nested mark (e.g., <bold><italic>text</italic></bold>)
    48	        result.push(...extractTextWithMarks(child, currentMarks));
    49	      } else {
    50	        // Block element inside mark - shouldn't happen but handle gracefully
    51	        result.push(...yjsElementToJson(child));
    52	      }
    53	    }
    54	  }
    55	
    56	  return result;
    57	}
    58	
    59	/**
    60	 * Convert Yjs XmlFragment to TipTap JSON
    61	 * This is used when reading documents that were edited via the collaborative editor
    62	 */
    63	export function yjsToJson(fragment: Y.XmlFragment): unknown {
    64	  const content: TipTapNode[] = [];
    65	
    66	  for (let i = 0; i < fragment.length; i++) {
    67	    const item = fragment.get(i);
