   161	/**
   162	 * Convert TipTap JSON content to Yjs XmlFragment
   163	 * Must be called within a transaction for proper Yjs integration
   164	 */
   165	export function jsonToYjs(doc: Y.Doc, fragment: Y.XmlFragment, content: unknown) {
   166	  if (!isTipTapDoc(content)) return;
   167	
   168	  doc.transact(() => {
   169	    for (const node of content.content) {
   170	      if (node.type === 'text') {
   171	        // Text node - create, push to parent first, then modify
   172	        const text = new Y.XmlText();
   173	        fragment.push([text]);
   174	        text.insert(0, node.text || '');
   175	        if (node.marks) {
   176	          const attrs: TipTapAttributes = {};
   177	          for (const mark of node.marks) {
   178	            attrs[mark.type] = mark.attrs || true;
   179	          }
   180	          text.format(0, text.length, attrs);
   181	        }
   182	      } else {
   183	        // Element node (paragraph, heading, bulletList, listItem, etc.)
   184	        const element = new Y.XmlElement(node.type);
   185	        fragment.push([element]);
   186	        // Set attributes after adding to parent
   187	        if (node.attrs) {
   188	          for (const [key, value] of Object.entries(node.attrs)) {
   189	            element.setAttribute(key, String(value));
   190	          }
   191	        }
   192	        // Recursively add children
   193	        if (node.content) {
   194	          jsonToYjsChildren(element, node.content);
   195	        }
   196	      }
   197	    }
   198	  });
   199	}
