   201	/**
   202	 * Helper to add children without wrapping in another transaction
   203	 */
   204	function jsonToYjsChildren(parent: Y.XmlElement, children: TipTapNode[]) {
   205	  for (const node of children) {
   206	    if (node.type === 'text') {
   207	      const text = new Y.XmlText();
   208	      parent.push([text]);
   209	      text.insert(0, node.text || '');
   210	      if (node.marks) {
   211	        const attrs: TipTapAttributes = {};
   212	        for (const mark of node.marks) {
   213	          attrs[mark.type] = mark.attrs || true;
   214	        }
   215	        text.format(0, text.length, attrs);
   216	      }
   217	    } else {
   218	      const element = new Y.XmlElement(node.type);
   219	      parent.push([element]);
   220	      if (node.attrs) {
   221	        for (const [key, value] of Object.entries(node.attrs)) {
   222	          element.setAttribute(key, String(value));
   223	        }
   224	      }
   225	      if (node.content) {
   226	        jsonToYjsChildren(element, node.content);
   227	      }
   228	    }
   229	  }
   230	}
   231	
   232	/**
   233	 * Load document content from Yjs binary state
   234	 * Returns TipTap JSON content or null if unable to convert
   235	 */
   236	export function loadContentFromYjsState(yjsState: Buffer): unknown | null {
   237	  try {
   238	    const doc = new Y.Doc();
   239	    Y.applyUpdate(doc, yjsState);
   240	    const fragment = doc.getXmlFragment('default');
   241	    return yjsToJson(fragment);
   242	  } catch (err) {
   243	    console.error('Failed to load content from Yjs state:', err);
   244	    return null;
   245	  }
