    75	/**
    76	 * Get timestamp column updates based on state transitions
    77	 *
    78	 * Returns SQL expressions for updating started_at, completed_at, etc.
    79	 * when an issue's state changes.
    80	 *
    81	 * @example
    82	 * const updates = getTimestampUpdates('triage', 'in_progress');
    83	 * // Returns: { started_at: 'COALESCE(started_at, NOW())' }
    84	 */
    85	export function getTimestampUpdates(
    86	  oldState: string | null,
    87	  newState: string
    88	): Record<string, string> {
    89	  const updates: Record<string, string> = {};
    90	
    91	  if (newState === 'in_progress' && oldState !== 'in_progress') {
    92	    if (oldState === 'done' || oldState === 'cancelled') {
    93	      // Reopening from done/cancelled
    94	      updates.reopened_at = 'NOW()';
    95	    } else {
    96	      // First time starting work
    97	      updates.started_at = 'COALESCE(started_at, NOW())';
    98	    }
    99	  }
   100	  if (newState === 'done' && oldState !== 'done') {
   101	    updates.completed_at = 'COALESCE(completed_at, NOW())';
   102	  }
   103	  if (newState === 'cancelled' && oldState !== 'cancelled') {
   104	    updates.cancelled_at = 'NOW()';
   105	  }
   106	
   107	  return updates;
   108	}
