   114	/**
   115	 * Get belongs_to associations for a document from junction table
   116	 *
   117	 * Returns array of associations with their type, title, and color.
   118	 *
   119	 * @example
   120	 * const associations = await getBelongsToAssociations(issueId);
   121	 * // Returns: [{ id: '...', type: 'project', title: 'My Project', color: '#ff0000' }]
   122	 */
   123	export async function getBelongsToAssociations(
   124	  documentId: string,
   125	  visibility?: AssociationVisibilityScope,
   126	): Promise<BelongsToEntry[]> {
   127	  const query = visibility
   128	    ? `SELECT da.related_id as id, da.relationship_type as type,
   129	              d.title, d.properties->>'color' as color
   130	       FROM document_associations da
   131	       JOIN documents d
   132	         ON da.related_id = d.id
   133	        AND d.workspace_id = $2
   134	        AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
   135	       WHERE da.document_id = $1
   136	       ORDER BY da.relationship_type, da.created_at`
   137	    : `SELECT da.related_id as id, da.relationship_type as type,
   138	              d.title, d.properties->>'color' as color
   139	       FROM document_associations da
   140	       LEFT JOIN documents d ON da.related_id = d.id
   141	       WHERE da.document_id = $1
   142	       ORDER BY da.relationship_type, da.created_at`;
   143	  const params = visibility
   144	    ? [documentId, visibility.workspaceId, visibility.userId, visibility.isAdmin]
   145	    : [documentId];
   146	  const result = await pool.query(query, params);
   147	  return result.rows.map((row) => ({
   148	    id: row.id,
   149	    type: row.type,
   150	    title: row.title || undefined,
   151	    color: row.color || undefined,
   152	  }));
   153	}
