   155	/**
   156	 * Batch version of getBelongsToAssociations to avoid N+1 queries
   157	 *
   158	 * Fetches associations for multiple documents in one query, returning
   159	 * a Map keyed by document ID.
   160	 *
   161	 * @example
   162	 * const associationsMap = await getBelongsToAssociationsBatch(issueIds);
   163	 * for (const issue of issues) {
   164	 *   issue.belongs_to = associationsMap.get(issue.id) || [];
   165	 * }
   166	 */
   167	export async function getBelongsToAssociationsBatch(
   168	  documentIds: string[],
   169	  visibility?: AssociationVisibilityScope,
   170	): Promise<Map<string, BelongsToEntry[]>> {
   171	  if (documentIds.length === 0) {
   172	    return new Map();
   173	  }
   174	
   175	  const query = visibility
   176	    ? `SELECT da.document_id, da.related_id as id, da.relationship_type as type,
   177	              d.title, d.properties->>'color' as color
   178	       FROM document_associations da
   179	       JOIN documents d
   180	         ON da.related_id = d.id
   181	        AND d.workspace_id = $2
   182	        AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
   183	       WHERE da.document_id = ANY($1)
   184	       ORDER BY da.document_id, da.relationship_type, da.created_at`
   185	    : `SELECT da.document_id, da.related_id as id, da.relationship_type as type,
   186	              d.title, d.properties->>'color' as color
   187	       FROM document_associations da
   188	       LEFT JOIN documents d ON da.related_id = d.id
   189	       WHERE da.document_id = ANY($1)
   190	       ORDER BY da.document_id, da.relationship_type, da.created_at`;
   191	  const params = visibility
   192	    ? [documentIds, visibility.workspaceId, visibility.userId, visibility.isAdmin]
   193	    : [documentIds];
   194	  const result = await pool.query(query, params);
   195	
   196	  // Group results by document_id
   197	  const associationsMap = new Map<string, BelongsToEntry[]>();
   198	  for (const row of result.rows) {
   199	    const docId = row.document_id;
   200	    if (!associationsMap.has(docId)) {
   201	      associationsMap.set(docId, []);
   202	    }
   203	    associationsMap.get(docId)!.push({
   204	      id: row.id,
   205	      type: row.type,
   206	      title: row.title || undefined,
   207	      color: row.color || undefined,
   208	    });
   209	  }
   210	
   211	  return associationsMap;
   212	}
