    14	/**
    15	 * Get visibility filter context for SQL queries.
    16	 * Returns the isAdmin boolean that should be used with visibility filter SQL.
    17	 *
    18	 * The visibility filter pattern is:
    19	 *   (visibility = 'workspace' OR created_by = $userId OR $isAdmin = TRUE)
    20	 *
    21	 * This allows:
    22	 * - All workspace-visible documents to be seen by everyone
    23	 * - Private documents to be seen only by their creator
    24	 * - Admins to see all documents
    25	 */
    26	export async function getVisibilityContext(
    27	  userId: string,
    28	  workspaceId: string
    29	): Promise<{ isAdmin: boolean }> {
    30	  const isAdmin = await isWorkspaceAdmin(userId, workspaceId);
    31	  return { isAdmin };
    32	}
    33	
    34	/**
    35	 * SQL fragment for visibility filtering.
    36	 * Use with parameterized queries where:
    37	 * - $N is userId
    38	 * - $N+1 is isAdmin boolean
    39	 *
    40	 * Example:
    41	 *   const { isAdmin } = await getVisibilityContext(userId, workspaceId);
    42	 *   const query = `
    43	 *     SELECT * FROM documents d
    44	 *     WHERE d.workspace_id = $1
    45	 *       AND ${VISIBILITY_FILTER_SQL('d', '$2', '$3')}
    46	 *   `;
    47	 *   await pool.query(query, [workspaceId, userId, isAdmin]);
    48	 */
    49	export function VISIBILITY_FILTER_SQL(
    50	  tableAlias: string,
    51	  userIdParam: string,
    52	  isAdminParam: string
    53	): string {
    54	  return `(${tableAlias}.visibility = 'workspace' OR ${tableAlias}.created_by = ${userIdParam} OR ${isAdminParam} = TRUE)`;
    55	}
