   124	 */
   125	export async function getBelongsToAssociations(
   126	  documentId: string,
   127	  visibility?: AssociationVisibilityScope | VisibilityJoinScope,
   128	): Promise<BelongsToEntry[]> {
   129	  const query = visibility
   130	    ? `SELECT da.related_id as id, da.relationship_type as type,
   131	              d.title, d.properties->>'color' as color
   132	       FROM document_associations da
   133	       JOIN documents d
   134	         ON da.related_id = d.id
   135	        AND d.workspace_id = $2
   136	        AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
   137	       WHERE da.document_id = $1
   138	       ORDER BY da.relationship_type, da.created_at`
   139	    : `SELECT da.related_id as id, da.relationship_type as type,
   140	              d.title, d.properties->>'color' as color
   141	       FROM document_associations da
   142	       LEFT JOIN documents d ON da.related_id = d.id
   143	       WHERE da.document_id = $1
   144	       ORDER BY da.relationship_type, da.created_at`;
   145	  const params = visibility
   146	    ? [documentId, visibility.workspaceId, visibility.userId, visibility.isAdmin]
   147	    : [documentId];
   148	  const result = await pool.query(query, params);
   149	  return result.rows.map((row) => ({
   150	    id: row.id,
   151	    type: row.type,
   152	    title: row.title || undefined,
   153	    color: row.color || undefined,
   154	  }));
   155	}
   156	
   157	/**
   158	 * Batch version of getBelongsToAssociations to avoid N+1 queries
   159	 *
   160	 * Fetches associations for multiple documents in one query, returning
   161	 * a Map keyed by document ID.
   162	 *
   163	 * @example
   164	 * const associationsMap = await getBelongsToAssociationsBatch(issueIds);
   165	 * for (const issue of issues) {
   166	 *   issue.belongs_to = associationsMap.get(issue.id) || [];
   167	 * }
   168	 */
   169	export async function getBelongsToAssociationsBatch(
   170	  documentIds: string[],
   171	  visibility?: AssociationVisibilityScope | VisibilityJoinScope,
   172	): Promise<Map<string, BelongsToEntry[]>> {
   173	  if (documentIds.length === 0) {
   174	    return new Map();
   175	  }
   176	
   177	  const query = visibility
   178	    ? `SELECT da.document_id, da.related_id as id, da.relationship_type as type,
   179	              d.title, d.properties->>'color' as color
   180	       FROM document_associations da
   181	       JOIN documents d
   182	         ON da.related_id = d.id
   183	        AND d.workspace_id = $2
   184	        AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
   185	       WHERE da.document_id = ANY($1)
   186	       ORDER BY da.document_id, da.relationship_type, da.created_at`
   187	    : `SELECT da.document_id, da.related_id as id, da.relationship_type as type,
   188	              d.title, d.properties->>'color' as color
   189	       FROM document_associations da
   190	       LEFT JOIN documents d ON da.related_id = d.id
   191	       WHERE da.document_id = ANY($1)
   192	       ORDER BY da.document_id, da.relationship_type, da.created_at`;
   193	  const params = visibility
   194	    ? [documentIds, visibility.workspaceId, visibility.userId, visibility.isAdmin]
   195	    : [documentIds];
   196	  const result = await pool.query(query, params);
   197	
   198	  // Group results by document_id
   199	  const associationsMap = new Map<string, BelongsToEntry[]>();
   200	  for (const row of result.rows) {
   201	    const docId = row.document_id;
   202	    if (!associationsMap.has(docId)) {
   203	      associationsMap.set(docId, []);
   204	    }
   205	    associationsMap.get(docId)!.push({
   206	      id: row.id,
   207	      type: row.type,
   208	      title: row.title || undefined,
   209	      color: row.color || undefined,
   210	    });
   211	  }
   212	
   213	  return associationsMap;
   214	}
   215	
   216	/**
   217	 * Sync belongs_to associations for a document
   218	 *
   219	 * Clears existing associations and creates new ones from the provided array.
   220	 * Each entry should have { id, type } at minimum.
   221	 *
   222	 * @example
   223	 * await syncBelongsToAssociations(issueId, [
   224	 *   { id: projectId, type: 'project' },
   225	 *   { id: sprintId, type: 'sprint' }
   226	 * ]);
   227	 */
   228	export async function syncBelongsToAssociations(
   229	  documentId: string,
   230	  associations: Array<{ id: string; type: string }>,
   231	  queryRunner?: { query: typeof pool.query }
   232	): Promise<void> {
   233	  const db = queryRunner || pool;
   234	  // Delete existing associations
   235	  await db.query(
   236	    'DELETE FROM document_associations WHERE document_id = $1',
   237	    [documentId]
   238	  );
   239	
   240	  // Insert new associations","total_lines":655}

